function HUD({ onTweaks }) {
  const [time, setTime] = React.useState("--:--:--");
  React.useEffect(() => {
    const tick = () => {
      const d = new Date();
      const p = (n) => String(n).padStart(2, "0");
      setTime(`${p(d.getHours())}:${p(d.getMinutes())}:${p(d.getSeconds())}`);
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, []);
  return (
    <div className="hud">
      <div className="hud-left">
        <span>
          <span className="hud-dot" /> SYS.ONLINE
        </span>
        <span>{CONFIG.hud.systemLabel}</span>
      </div>
      <div className="hud-right">
        <span>
          LAT <span className="hud-coord">{CONFIG.hud.lat}</span>
        </span>
        <span>
          LNG <span className="hud-coord">{CONFIG.hud.lng}</span>
        </span>
        <span>{time}</span>
        <button className="hud-tweaks-btn" onClick={onTweaks} title="Open tweaks panel" style={{ display: "none" }}>
          ⚙ Tweaks
        </button>
      </div>
    </div>
  );
}

