function Particles() {
  const ref = React.useRef(null);
  React.useEffect(() => {
    const cv = ref.current;
    if (!cv) return;
    const ctx = cv.getContext("2d");
    let raf, w, h;
    const stars = [];
    const resize = () => {
      w = cv.width = window.innerWidth;
      h = cv.height = window.innerHeight;
    };
    resize();
    window.addEventListener("resize", resize);
    for (let i = 0; i < 80; i++) {
      stars.push({
        x: Math.random() * 1920,
        y: Math.random() * 1080,
        z: Math.random(),
        vy: 0.1 + Math.random() * 0.4,
      });
    }
    const tick = () => {
      ctx.clearRect(0, 0, w, h);
      stars.forEach((s) => {
        s.y += s.vy;
        if (s.y > h) {
          s.y = 0;
          s.x = Math.random() * w;
        }
        const a = 0.2 + s.z * 0.6;
        ctx.fillStyle = `rgba(217, 70, 239, ${a})`;
        ctx.fillRect(s.x % w, s.y, 1 + s.z * 1.5, 1 + s.z * 1.5);
      });
      raf = requestAnimationFrame(tick);
    };
    tick();
    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener("resize", resize);
    };
  }, []);
  return <canvas ref={ref} />;
}

function App() {
  const [t, setTweak] = useTweaks(TWEAK_DEFAULTS);
  const [active, setActive] = React.useState("home");

  const openTweaks = () => {
    window.postMessage({ type: "__activate_edit_mode" }, "*");
  };

  React.useEffect(() => {
    const root = document.documentElement;
    const toRgb = (hex) => {
      const m = hex.replace("#", "");
      const r = parseInt(m.slice(0, 2), 16);
      const g = parseInt(m.slice(2, 4), 16);
      const b = parseInt(m.slice(4, 6), 16);
      return `${r} ${g} ${b}`;
    };
    root.style.setProperty("--accent", t.accent);
    root.style.setProperty("--accent-2", t.accent2);
    root.style.setProperty("--accent-glow", toRgb(t.accent));
    root.style.setProperty("--grid", `rgba(${toRgb(t.accent)}, 0.08)`);
    root.style.setProperty("--line", `rgba(${toRgb(t.accent)}, 0.18)`);
    root.style.setProperty("--line-strong", `rgba(${toRgb(t.accent)}, 0.42)`);

    const pair = FONT_PAIRS[t.fontPair];
    root.style.setProperty("--font-display", pair.display);
    root.style.setProperty("--font-body", pair.body);
    root.style.setProperty("--font-mono", pair.mono);

    const id = "gf-" + t.fontPair;
    if (!document.getElementById(id)) {
      const link = document.createElement("link");
      link.id = id;
      link.rel = "stylesheet";
      link.href = `https://fonts.googleapis.com/css2?family=${pair.google}&display=swap`;
      document.head.appendChild(link);
    }

    const dens = { compact: 0.75, regular: 1, comfy: 1.3 }[t.density] || 1;
    root.style.setProperty("--gap", dens);

    const anim = { off: 0, low: 0.5, high: 1 }[t.animation] ?? 1;
    root.style.setProperty("--anim", anim);

    document.body.dataset.bg = t.background;
  }, [t]);

  React.useEffect(() => {
    const sections = document.querySelectorAll("section[id]");
    const obs = new IntersectionObserver(
      (entries) => {
        entries.forEach((e) => {
          if (e.isIntersecting) setActive(e.target.id);
        });
      },
      { rootMargin: "-40% 0px -40% 0px" }
    );
    sections.forEach((s) => obs.observe(s));
    return () => obs.disconnect();
  }, []);

  React.useEffect(() => {
    const els = document.querySelectorAll(".reveal, .skill-cell");
    const obs = new IntersectionObserver(
      (entries) => {
        entries.forEach((e) => {
          if (e.isIntersecting) e.target.classList.add("in-view");
        });
      },
      { threshold: 0.15 }
    );
    els.forEach((el) => obs.observe(el));
    return () => obs.disconnect();
  }, []);

  return (
    <>
      <div className="bg-layer bg-vignette" />
      <div className="bg-layer bg-grid" />
      <div className="bg-layer bg-noise" />
      <div className="bg-layer bg-particles">
        <Particles />
      </div>
      <div className="scanlines" />

      <HUD onTweaks={openTweaks} />
      <SectionNav active={active} />

      <Hero />
      <Marquee />
      <SkillSection id="web" skillKey="web" />
      <SkillSection id="automation" skillKey="automation" />
      <SkillSection id="aws" skillKey="aws" extra={<AwsCerts />} />
      <SkillSection id="mobile" skillKey="mobile" />
      <Contact />

      <TweaksPanel title="Tweaks">
        <TweakSection label="Color" />
        <TweakColor label="Accent" value={t.accent} onChange={(v) => setTweak("accent", v)} />
        <TweakColor
          label="Accent 2"
          value={t.accent2}
          onChange={(v) => setTweak("accent2", v)}
        />
        <TweakSection label="Typography" />
        <TweakSelect
          label="Font pair"
          value={t.fontPair}
          options={[
            { value: "grotesk-mono", label: "Space Grotesk × JetBrains" },
            { value: "syne-ibm", label: "Syne × IBM Plex" },
            { value: "anton-jet", label: "Anton × JetBrains" },
            { value: "orbitron-rajdhani", label: "Orbitron × Rajdhani" },
          ]}
          onChange={(v) => setTweak("fontPair", v)}
        />
        <TweakSection label="Background" />
        <TweakRadio
          label="Style"
          value={t.background}
          options={["solid", "grid", "particles"]}
          onChange={(v) => setTweak("background", v)}
        />
        <TweakSection label="Layout" />
        <TweakRadio
          label="Density"
          value={t.density}
          options={["compact", "regular", "comfy"]}
          onChange={(v) => setTweak("density", v)}
        />
        <TweakSection label="Motion" />
        <TweakRadio
          label="Animation"
          value={t.animation}
          options={["off", "low", "high"]}
          onChange={(v) => setTweak("animation", v)}
        />
      </TweaksPanel>
    </>
  );
}

export default App;
